import React, { useState } from "react";

// MUST match your backend domain
const apiBase = "https://prasa-app-yde3.onrender.com";

function Login({ onLoginSuccess }) {
  const [empld, setEmpld] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");

    if (!empld || !password) {
      setError("Please enter Employee ID and Password.");
      return;
    }

    try {
      setLoading(true);

      const response = await fetch(`${apiBase}/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ login_id: empld, password }),
      });

      const data = await response.json();

      if (!response.ok || !data.success) {
        setError(data.message || "Invalid credentials");
      } else {
        onLoginSuccess(data.employee);
      }
    } catch (err) {
      console.error("Login Error:", err);
      setError("Server error. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">

        {/* LOGO */}
        <img
          src="/logo.png"
          alt="PRASA Logo"
          style={{
            width: 90,
            height: 90,
            marginBottom: 8,
            objectFit: "contain",
          }}
        />

        {/* NEW PORTAL TITLE */}
        <h2 className="title">PRASA Employee Portal</h2>

        <form onSubmit={handleLogin}>
          <input
            type="text"
            placeholder="Enter EMPID"
            value={empld}
            onChange={(e) => setEmpld(e.target.value)}
            className="input-box"
          />

          <input
            type="password"
            placeholder="Enter Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="input-box"
          />

          <button type="submit" className="btn-login" disabled={loading}>
            {loading ? "Logging in..." : "Login"}
          </button>
        </form>

        {error && <p style={{ color: "red", marginTop: 10 }}>{error}</p>}
      </div>
    </div>
  );
}

export default Login;
